CREATE TABLE IF NOT EXISTS users(id SERIAL PRIMARY KEY,name TEXT NOT NULL,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,role TEXT NOT NULL DEFAULT 'administrator',is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS slides(id SERIAL PRIMARY KEY,title TEXT NOT NULL,subtitle TEXT,image_url TEXT,button_text TEXT,button_url TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS services(id SERIAL PRIMARY KEY,title TEXT NOT NULL,slug TEXT UNIQUE,summary TEXT,description TEXT,image_url TEXT,icon TEXT,display_order INT DEFAULT 0,is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS products(id SERIAL PRIMARY KEY,title TEXT NOT NULL,slug TEXT UNIQUE,category TEXT,summary TEXT,description TEXT,image_url TEXT,gallery_urls TEXT,features TEXT,display_order INT DEFAULT 0,is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS projects(id SERIAL PRIMARY KEY,title TEXT NOT NULL,slug TEXT UNIQUE,client TEXT,location TEXT,category TEXT,year TEXT,summary TEXT,description TEXT,image_url TEXT,gallery_urls TEXT,display_order INT DEFAULT 0,is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS news(id SERIAL PRIMARY KEY,title TEXT NOT NULL,slug TEXT UNIQUE,excerpt TEXT,body TEXT,image_url TEXT,published_at DATE,display_order INT DEFAULT 0,is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS gallery_items(id SERIAL PRIMARY KEY,title TEXT NOT NULL,category TEXT,image_url TEXT NOT NULL,description TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS testimonials(id SERIAL PRIMARY KEY,client_name TEXT NOT NULL,company TEXT,quote TEXT,image_url TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS clients(id SERIAL PRIMARY KEY,name TEXT NOT NULL,logo_url TEXT,website_url TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS downloads(id SERIAL PRIMARY KEY,title TEXT NOT NULL,category TEXT,file_url TEXT NOT NULL,description TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS vacancies(id SERIAL PRIMARY KEY,title TEXT NOT NULL,location TEXT,employment_type TEXT,description TEXT,requirements TEXT,deadline DATE,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS branches(id SERIAL PRIMARY KEY,name TEXT NOT NULL,address TEXT,phone_primary TEXT,phone_secondary TEXT,email TEXT,map_url TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS faqs(id SERIAL PRIMARY KEY,question TEXT NOT NULL,answer TEXT NOT NULL,category TEXT,keywords TEXT,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS quote_requests(id SERIAL PRIMARY KEY,name TEXT NOT NULL,company TEXT,phone TEXT NOT NULL,email TEXT,location TEXT,service TEXT,message TEXT NOT NULL,status TEXT DEFAULT 'new',assigned_to INT REFERENCES users(id),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS enquiries(id SERIAL PRIMARY KEY,name TEXT NOT NULL,email TEXT,phone TEXT,subject TEXT,message TEXT NOT NULL,status TEXT DEFAULT 'new',created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS audit_logs(id BIGSERIAL PRIMARY KEY,user_id INT REFERENCES users(id),action TEXT NOT NULL,module_name TEXT,record_id TEXT,details JSONB,created_at TIMESTAMPTZ DEFAULT NOW());

ALTER TABLE products ADD COLUMN IF NOT EXISTS gallery_urls TEXT;

CREATE TABLE IF NOT EXISTS gallery_images(id SERIAL PRIMARY KEY,title TEXT NOT NULL,description TEXT,caption TEXT,album TEXT,category TEXT,image_url TEXT NOT NULL,display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE,status TEXT DEFAULT 'published',created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
